public class OrganizationTreeBuilder {

    public static TreeNode buildOrganizationTree(String jsonFilePath) throws IOException {
        ObjectMapper mapper = new ObjectMapper();
        JsonNode rootArray = mapper.readTree(new File(jsonFilePath));

        TreeNode root = new TreeNode("Organization", 0);

        // Level 1 nodes (direct children of root)
        int level1Count = Math.min(3, rootArray.size());
        for (int i = 0; i < level1Count; i++) {
            JsonNode teamNode = rootArray.get(i);
            String teamName = teamNode.get("teamName").asText();
            int memberCount = teamNode.get("members").size();

            TreeNode level1Node = new TreeNode(teamName, memberCount);
            root.addChild(level1Node);

            // Level 2 nodes
            int startIdx = 3*i + level1Count;
            int level2Count = Math.min(3, rootArray.size() - startIdx);
            for (int j = 0; j < level2Count; j++) {
                int idx = startIdx + j;
                if (idx < rootArray.size()) {
                    JsonNode subTeamNode = rootArray.get(idx);
                    String subTeamName = subTeamNode.get("teamName").asText();
                    int subMemberCount = subTeamNode.get("members").size();

                    TreeNode level2Node = new TreeNode(subTeamName, subMemberCount);
                    level1Node.addChild(level2Node);

                    // Level 3 nodes
                    int startSubIdx = 3*idx + level2Count;
                    int level3Count = Math.min(3, rootArray.size() - startSubIdx);
                    for (int k = 0; k < level3Count; k++) {
                        int subIdx = startSubIdx + k;
                        if (subIdx < rootArray.size()) {
                            JsonNode leafTeamNode = rootArray.get(subIdx);
                            String leafTeamName = leafTeamNode.get("teamName").asText();
                            int leafMemberCount = leafTeamNode.get("members").size();

                            TreeNode level3Node = new TreeNode(leafTeamName, leafMemberCount);
                            level2Node.addChild(level3Node);
                        }
                    }
                }
            }
        }

        return root;
    }
}
