import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonParser;

public class LogAnalyzer {

    // Inner class to represent a log entry
    public static class LogEntry {
        private String timestamp;
        private String severity;
        private String message;

        public LogEntry(String timestamp, String severity, String message) {
            this.timestamp = timestamp;
            this.severity = severity;
            this.message = message;
        }

        public String getTimestamp() {
            return timestamp;
        }

        public String getSeverity() {
            return severity;
        }

        public String getMessage() {
            return message;
        }
    }

    // Output structure to hold categorized logs
    public static class LogAnalysisResult {
        private List<LogEntry> info;
        private List<LogEntry> warning;
        private List<LogEntry> error;

        public LogAnalysisResult() {
            this.info = new ArrayList<>();
            this.warning = new ArrayList<>();
            this.error = new ArrayList<>();
        }

        public List<LogEntry> getInfo() {
            return info;
        }

        public List<LogEntry> getWarning() {
            return warning;
        }

        public List<LogEntry> getError() {
            return error;
        }
    }

    // Method to analyze log file and categorize entries
    public LogAnalysisResult analyzeLogFile(String filePath) throws IOException {
        LogAnalysisResult result = new LogAnalysisResult();

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            JsonElement jsonElement = JsonParser.parseReader(reader);

            if (jsonElement.isJsonArray()) {
                JsonArray jsonArray = jsonElement.getAsJsonArray();

                for (JsonElement element : jsonArray) {
                    if (element.isJsonObject()) {
                        JsonObject logObject = element.getAsJsonObject();

                        String timestamp = logObject.get("timestamp").getAsString();
                        String severity = logObject.get("severity").getAsString();
                        String message = logObject.get("message").getAsString();

                        LogEntry logEntry = new LogEntry(timestamp, severity, message);

                        // Categorize by severity
                        switch (severity) {
                            case "info":
                                result.info.add(logEntry);
                                break;
                            case "warning":
                                result.warning.add(logEntry);
                                break;
                            case "error":
                                result.error.add(logEntry);
                                break;
                        }
                    }
                }
            }
        }

        return result;
    }
}
