fn analyze_products(products: &[HashMap<String, serde_json::Value>]) -> HashMap<String, bool> {
    let mut result = HashMap::new();

    for product in products {
        if let (Some(id), Some(price)) = (
            product.get("id").and_then(|v| v.as_str()),
