Here's a C++ function that processes a vector of Employee structs and constructs a hierarchical tree based on manager-employee relationships:

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

struct Employee {
    std::string name;
    std::vector<int> salaries;
};

struct TreeNode {
    std::string name;
    int maxSalary;
    std::vector<TreeNode*> children;

    TreeNode(const std::string& n, int s) : name(n), maxSalary(s) {}
    ~TreeNode() {
        for (auto child : children) {
            delete child;
        }
    }
};

TreeNode* buildEmployeeTree(const std::vector<Employee>& employees, 
                           const std::vector<std::pair<std::string, std::string>>& relationships) {
    // Create mapping of employee name to their data
    std::unordered_map<std::string, Employee> employeeMap;
    for (const auto& emp : employees) {
        employeeMap[emp.name] = emp;
    }

    // Find the maximum salary for each employee
    std::unordered_map<std::string, int> maxSalaries;
    for (const auto& emp : employees) {
        if (emp.salaries.empty()) {
            maxSalaries[emp.name] = 0;
        } else {
            maxSalaries[emp.name] = *std::max_element(emp.salaries.begin(), emp.salaries.end());
        }
    }

    // Create manager to employees mapping
    std::unordered_map<std::string, std::vector<std::string>> managerToEmployees;
    std::unordered_map<std::string, std::string> employeeToManager;

    for (const auto& relation : relationships) {
        managerToEmployees[relation.first].push_back(relation.second);
        employeeToManager[relation.second] = relation.first;
    }

    // Find the root (employee with no manager)
    std::string rootName;
    for (const auto& emp : employees) {
        if (employeeToManager.find(emp.name) == employeeToManager.end()) {
            rootName = emp.name;
            break;
        }
    }

    // Build the tree with depth limit = 3 and max 2 children per node
    std::function<TreeNode*(const std::string&, int)> buildTree = 
        [&](const std::string& empName, int depth) -> TreeNode* {
            if (depth > 3 || employeeMap.find(empName) == employeeMap.end()) {
                return nullptr;
            }

            TreeNode* node = new TreeNode(empName, maxSalaries[empName]);

            if (depth < 3 && managerToEmployees.find(empName) != managerToEmployees.end()) {
                auto& subordinates = managerToEmployees[empName];
                // Limit to max 2 children
                for (size_t i = 0; i < std::min(size_t(2), subordinates.size()); ++i) {
                    TreeNode* child = buildTree(subordinates[i], depth + 1);
                    if (child) {
                        node->children.push_back(child);
                    }
                }
            }

            return node;
        };

    return buildTree(rootName, 1);
}
