use std::collections::HashMap;
use std::fs::File;
use std::io::BufReader;
use serde::{Deserialize, Serialize};
use serde_json;

#[derive(Debug, Serialize, Deserialize)]
struct Edge {
    from: usize,
    to: usize,
    weight: usize,
}

#[derive(Debug, Serialize, Deserialize)]
struct RoadNetwork {
    edges: Vec<Edge>,
}

#[derive(Debug)]
struct Graph {
    adjacency_list: HashMap<usize, Vec<(usize, usize)>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            adjacency_list: HashMap::new(),
        }
    }

    fn add_edge(&mut self, from: usize, to: usize, weight: usize) {
        self.adjacency_list
            .entry(from)
            .or_insert_with(Vec::new)
            .push((to, weight));

        // For undirected graph
        self.adjacency_list
            .entry(to)
            .or_insert_with(Vec::new)
            .push((from, weight));
    }
}

fn analyze_road_network(file_path: &str) -> Result<Graph, Box<dyn std::error::Error>> {
    // Read JSON file
    let file = File::open(file_path)?;
    let reader = BufReader::new(file);
    let network: RoadNetwork = serde_json::from_reader(reader)?;

    // Validate constraints
    if network.edges.len() > 200 {
        return Err("Too many edges. Maximum allowed is 200.".into());
    }

    // Create graph
    let mut graph = Graph::new();

    for edge in network.edges {
        // Validate node IDs
        if edge.from < 1 || edge.from > 100 || edge.to < 1 || edge.to > 100 {
            return Err(format!("Invalid node ID in edge {}->{}: Node IDs must be in range [1, 100]", 
                              edge.from, edge.to).into());
        }

        // Validate edge weights
        if edge.weight < 1 || edge.weight > 50 {
            return Err(format!("Invalid weight {} for edge {}->{}: Weights must be in range [1, 50]", 
                              edge.weight, edge.from, edge.to).into());
        }

        // Add edge to graph
        graph.add_edge(edge.from, edge.to, edge.weight);
    }

    Ok(graph)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let graph = analyze_road_network("road_network.json")?;
    println!("Graph analysis complete: {:?}", graph);
    Ok(())
}
