import java.io.FileReader;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import org.json.simple.JSONArray;
import org.json.simple.JSONObject;
import org.json.simple.parser.JSONParser;

class Employee {
    int id;
    int salary;

    public Employee(int id, int salary) {
        this.id = id;
        this.salary = salary;
    }
}

class Node {
    int id;
    List<Edge> edges;

    public Node(int id) {
        this.id = id;
        this.edges = new ArrayList<>();
    }

    public void addEdge(Edge edge) {
        edges.add(edge);
    }
}

class Edge {
    Node target;
    int salaryDifference;

    public Edge(Node target, int salaryDifference) {
        this.target = target;
        this.salaryDifference = salaryDifference;
    }
}

class Graph {
    Map<Integer, Node> nodes;
    int edgeCount;

    public Graph() {
        nodes = new HashMap<>();
        edgeCount = 0;
    }

    public void addNode(int id) {
        if (!nodes.containsKey(id)) {
            nodes.put(id, new Node(id));
        }
    }

    public void addEdge(int sourceId, int targetId, int salaryDiff) {
        Node source = nodes.get(sourceId);
        Node target = nodes.get(targetId);

        if (source != null && target != null && edgeCount < 50) {
            source.addEdge(new Edge(target, salaryDiff));
            edgeCount++;
        }
    }
}

public class EmployeeGraphBuilder {

    public static Graph buildEmployeeSalaryGraph(String jsonFilePath) {
        Graph graph = new Graph();

        try {
            JSONParser parser = new JSONParser();
            FileReader reader = new FileReader(jsonFilePath);
            JSONArray employeesArray = (JSONArray) parser.parse(reader);

            List<Employee> employees = new ArrayList<>();

            // Parse employee data from JSON
            for (Object obj : employeesArray) {
                JSONObject employeeObj = (JSONObject) obj;
                int empId = ((Long) employeeObj.get("id")).intValue();
                int salary = ((Long) employeeObj.get("salary")).intValue();
                employees.add(new Employee(empId, salary));
            }

            // Assign node IDs within range [100, 999]
            Map<Integer, Integer> employeeToNodeId = new HashMap<>();
            int nodeIdCounter = 100;

            for (Employee emp : employees) {
                int nodeId = nodeIdCounter++;
                if (nodeId > 999) {
                    break; // Stop adding nodes if we exceed ID limit
                }

                employeeToNodeId.put(emp.id, nodeId);
                graph.addNode(nodeId);
            }

            // Create edges based on salary differences
            for (int i = 0; i < employees.size(); i++) {
                Employee emp1 = employees.get(i);
                Integer nodeId1 = employeeToNodeId.get(emp1.id);

                if (nodeId1 == null) continue;

                for (int j = i + 1; j < employees.size(); j++) {
                    Employee emp2 = employees.get(j);
                    Integer nodeId2 = employeeToNodeId.get(emp2.id);

                    if (nodeId2 == null) continue;

                    int salaryDiff = Math.abs(emp1.salary - emp2.salary);
                    if (salaryDiff < 5000) {
                        graph.addEdge(nodeId1, nodeId2, salaryDiff);

                        // Stop adding edges if we reach the limit
                        if (graph.edgeCount >= 50) {
                            break;
                        }
                    }
                }

                if (graph.edgeCount >= 50) {
                    break;
                }
            }

            reader.close();

        } catch (Exception e) {
            e.printStackTrace();
        }

        return graph;
    }
}
