Here's a C++ function that reads employee data from a CSV file, computes total hours worked for each employee, and returns the results in a fixed-size tuple:

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <map>
#include <vector>
#include <tuple>
#include <algorithm>
#include <cstdlib>

template <size_t N>
std::tuple<int, int, int, int, int> calculateEmployeeHours(const std::string& filename) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        throw std::runtime_error("Could not open file: " + filename);
    }

    std::string line;
    std::map<int, int> employeeHours;

    // Skip header line
    std::getline(file, line);

    // Process data
    while (std::getline(file, line)) {
        std::stringstream ss(line);
        std::string item;
        int employeeId = 0;
        int hours = 0;

        if (std::getline(ss, item, ',')) {
            employeeId = std::stoi(item);
        }

        if (std::getline(ss, item, ',')) {
            hours = std::stoi(item);
        }

        employeeHours[employeeId] += hours;
    }

    // Ensure hours are within allowed range [0, 160]
    for (auto& entry : employeeHours) {
        entry.second = std::min(160, std::max(0, entry.second));
    }

    // Sort employee IDs
    std::vector<int> ids;
    for (const auto& entry : employeeHours) {
        ids.push_back(entry.first);
    }
    std::sort(ids.begin(), ids.end());

    // Ensure we have exactly N unique employees
    if (ids.size() != N) {
        throw std::runtime_error("Expected " + std::to_string(N) + 
                                " unique employees, but found " + 
                                std::to_string(ids.size()));
    }

    // Create tuple with employee hours
    std::tuple<int, int, int, int, int> result;
    for (size_t i = 0; i < N; ++i) {
        std::get<0>(result) = (i == 0) ? employeeHours[ids[0]] : std::get<0>(result);
        std::get<1>(result) = (i == 1) ? employeeHours[ids[1]] : std::get<1>(result);
        std::get<2>(result) = (i == 2) ? employeeHours[ids[2]] : std::get<2>(result);
        std::get<3>(result) = (i == 3) ? employeeHours[ids[3]] : std::get<3>(result);
        std::get<4>(result) = (i == 4) ? employeeHours[ids[4]] : std::get<4>(result);
    }

    return result;
}
