struct TreeNode {
    id: i32,
    children: Vec<TreeNode>,
}

fn build_tree(nodes: &[(i32, i32)], max_depth: usize, max_children: usize) -> Option<TreeNode> {
    // Find the root node
    if nodes.is_empty() {
        return None;
    }

    // Build adjacency list
    let mut children_map: std::collections::HashMap<i32, Vec<i32>> = std::collections::HashMap::new();

    for &(node_id, parent_id) in nodes {
        children_map.entry(parent_id).or_insert_with(Vec::new).push(node_id);
    }

    // Build tree recursively
    fn build_node(id: i32, depth: usize, 
                 children_map: &std::collections::HashMap<i32, Vec<i32>>, 
                 max_depth: usize, 
                 max_children: usize) -> TreeNode {
        let mut node = TreeNode { id, children: Vec::new() };

        if depth < max_depth {
            if let Some(child_ids) = children_map.get(&id) {
                // Limit to max_children
                for &child_id in child_ids.iter().take(max_children) {
                    node.children.push(build_node(child_id, depth + 1, children_map, max_depth, max_children));
                }
            }
        }

        node
    }

    // Start with root (0)
    Some(build_node(0, 0, &children_map, max_depth, max_children))
}
