fn get_recent_unique_timestamps(timestamps: Vec<i64>) -> std::collections::HashSet<i64> {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs() as i64;
    let one_hour_ago = now - 3600;

    timestamps.into_iter()
        .filter(|&ts| ts >= one_hour_ago && ts <= now)
        .collect::<std::collections::HashSet<i64>>()
        .into_iter()
        .take(10)
        .collect()
}
