public List<Integer> evaluateExpressions(String input) {
    List<Integer> results = new ArrayList<>();
    String[] lines = input.split("\n");

    for (String line : lines) {
        line = line.trim();
        if (line.isEmpty()) continue;

        int result = (int) new javax.script.ScriptEngineManager()
            .getEngineByName("JavaScript")
            .eval(line);

        results.add(Math.max(0, result));
    }

    return results;
}
